import Navbar from "../components/Navbar";
import BottomBar from "../components/BottomBar";
import Sidebar from "../components/Sidebar";
import MessageBar from "../components/MessageBar";

// different types of cards
import Category from "../components/Categories";
import SquareFc from "../components/SquareFC";
import HorizontalFc from "../components/HorizontalFC";
import HorizontalRounded from "../components/HorizontalRounded";

//supporting UI components
import Loader from "../components/Loader";
import Subheadsee from "../atomic/Subheading";
import Subheading from "../atomic/atomic";
import { ShortMsg } from "../components/MessageBar";
import { SeeMore, Heartclick } from "../atomic/atomic";

//Hooks, navigation, other essential components
import { useEffect, useState } from "react";
import { Helmet } from "react-helmet-async";
import { Link, useLocation, useNavigate } from "react-router-dom";

//images for showing categories
const images = {
  drinks:
    "data:image/jpeg;base64,",
  snacks:
    "data:image/jpeg;base64,",
  dessert:
    "data:image/jpeg;base64,",
  sweets:
    "data:image/jpeg;base64,",
};

//starting of home component
const Home = () => {
  //loader state
  const [loader, setLoader] = useState(true);

  //variables for type/category/tag of foods and user
  const [trending, setTrending] = useState([]);
  const [popular, setPopular] = useState([]);
  const [bestSeller, setBestSeller] = useState([]);
  const [recommended, setRecommended] = useState([]);
  const [chefChoice, setChefChoice] = useState([]);

  const [favFoods, setFavFoods] = useState([]);
  const [user, setUser] = useState({
    username: "",
    email: "",
  });
  let isLoggedIn = false;

  //handle guest users
  const [guestFav, setGuestFav] = useState([]);
  const [guestCart, setGuestCart] = useState([]);

  //fetching all food data and user data
  useEffect(() => {
    async function getData() {
      try {
        //fetch all food data
        const res = await fetch(`${import.meta.env.VITE_API_URL}`);
        const {
          trendingFood,
          popularFood,
          recommendedFood,
          bestSellerFood,
          chefChoiceFood,
        } = await res.json();

        if (
          trendingFood &&
          popularFood &&
          recommendedFood &&
          bestSellerFood &&
          chefChoiceFood
        ) {
          setLoader(false);
          setTrending(trendingFood.slice(0, 10));
          setPopular(popularFood.slice(0, 4));
          setRecommended(recommendedFood.slice(0, 4));
          setBestSeller(bestSellerFood.slice(0, 8));
          setChefChoice(chefChoiceFood.slice(0, 4));
        }

        //checking user is logged in or not
        const response = await fetch(
          `${import.meta.env.VITE_API_URL}/user/profile`,
          {
            credentials: "include",
          },
        );
        const userData = await response.json();
        if (userData.code === "NL" || userData.code === "NU") {
          isLoggedIn = false;
          sessionStorage.setItem("user", false);
          console.log(userData.message);
          return;
        } else {
          isLoggedIn = true;
          sessionStorage.setItem("user", true);
          // console.log(isLoggedIn);
          setUser(userData);
        }

        //extract fav foods for icon state, only when user logged in
        const data = await fetch(
          `${import.meta.env.VITE_API_URL}/user/favourite`,
          {
            credentials: "include",
          },
        );
        const { favourites } = await data.json();
        setFavFoods(favourites);
      } catch (err) {
        console.error(err);
      }
    }
    getData();
  }, [isLoggedIn]);

  const [showSide, setShowSide] = useState(false); //sidebar logic
  const showSideBar = () => {
    setShowSide(!showSide);
  };

  //satisfaction messages
  const location = useLocation();
  const navigate = useNavigate();
  const [message, setMessage] = useState(location.state?.message || "");

  useEffect(() => {
    if (location.state?.message) {
      navigate(location.pathname, {
        replace: true,
        state: null,
      });
    }
  }, []);

  const [msg, setMsg] = useState(null);
  const [update, setUpdate] = useState(false);
  useEffect(() => {
    if (!msg) return;

    const timer = setTimeout(() => {
      setMsg(null);
      setUpdate(!update);
    }, 2000); // 3 seconds

    return () => clearTimeout(timer);
  }, [msg]);
  // let bing=sessionStorage.getItem("user");
  // console.log(bing);

  function satisfymessage(text) {
    setMsg(text);
    setUpdate(!update);
  }
  return (
    <div>
      <Helmet>
        <title>BiteBox | The Home of Deliciousness</title>
      </Helmet>

      {/* satisfaction message component */}
      {message && <MessageBar message={message} />}
      {msg && <ShortMsg message={msg} />}
      {/* home page navbar, sidebar function and user data */}
      <Navbar onClick={showSideBar} user={user} />
      {loader && <Loader />}
      {/* sidebar component */}
      {showSide && <Sidebar onClick={showSideBar} showSide={showSide} />}

      <h1 className="ml-3 my-0 mt-1.5 flex font-bold text-gray-400 text-md">
        Are you Hungry
        {/* <Utensils strokeWidth={1} className="w-5" /> */}
      </h1>
      <h1 className="ml-3 my-0 font-extrabold text-xl">
        What meal do you Want?
      </h1>

      {/* hero section  */}
      <section className="flex overflow-x-auto mt-2 gap-4 h-60 relative px-[5%] snap-x snap-mandatory scroll-smooth no-scrollbar">
        {/* <HeroImage image={} /> */}
        {/* Dynamic Dots Indicator */}
        {/* <ul className="absolute bottom-4 left-1/2 -translate-x-1/2 flex gap-1 z-10">
          <li className="rounded-full w-6 h-2 transition-colors duration-300 bg-white"></li>
          <li className="rounded-full w-6 h-2 transition-colors duration-300 bg-white/50"></li>
          <li className="rounded-full w-6 h-2 transition-colors duration-300 bg-white/50"></li>
          <li className="rounded-full w-6 h-2 transition-colors duration-300 bg-white/50"></li>
          <li className="rounded-full w-6 h-2 transition-colors duration-300 bg-white/50"></li>
        </ul> */}
      </section>

      {/* catgories section  */}
      <section className="mb-4">
        <Subheadsee subHeading="Categories" path="/categories" />
        <div className="flex justify-evenly">
          <Category text="Snacks" image={images.snacks} />
          <Category text="Sweets" image={images.sweets} />
          <Category text="Dessert" image={images.dessert} />
          <Category text="Drinks" image={images.drinks} />
        </div>
      </section>

      {/* trending now  */}
      <section className="mb-2 px-4">
        <Subheading title="Trending Now" className="ml-4" />
        <div className=" flex items-center overflow-x-auto gap-5 py-3 scrollbar-none">
          {trending.map((item) => (
            <SquareFc
              key={item._id}
              image={item.image}
              name={item.name}
              servingQuantity={item.servingQuantity}
              quantity={item.quantity}
              price={item.price}
              unit={item.unit}
              category={item.Category}
              id={item._id}
              isFav={favFoods.some((food) => food._id === item._id)}
              satisfymessage={satisfymessage}
              description={item.description}
            />
          ))}
          <Link to={`/tag/trending`}>
            <SeeMore text="See More" />
          </Link>
        </div>
      </section>

      {/* Popular meals section  */}
      <section className="mb-5">
        <Subheadsee subHeading="Popular Meals" path="/tag/popular" />
        <div className="px-5">
          {popular.map((item) => (
            <HorizontalFc
              key={item._id}
              image={item.image}
              name={item.name}
              description={item.description}
              servingQuantity={item.servingQuantity}
              quantity={item.quantity}
              price={item.price}
              unit={item.unit}
              id={item._id}
              isFav={favFoods.some((food) => food._id === item._id)}
              satisfymessage={satisfymessage}
            />
          ))}
        </div>
      </section>

      {/* best seller */}
      <section className="mb-2 px-4">
        <Subheading title="Best Seller" className="ml-4" />
        <div className=" flex items-center overflow-x-auto gap-3 py-3 scrollbar-none">
          {bestSeller.map((item) => (
            <HorizontalRounded
              key={item._id}
              id={item._id}
              image={item.image}
              name={item.name}
              servingQuantity={item.servingQuantity}
              quantity={item.quantity}
              unit={item.unit}
              price={item.price}
            />
          ))}
          <Link to={`/tag/bestseller`}>
            <SeeMore text="See More" />
          </Link>
        </div>
      </section>

      {/* recommended for you*/}
      <section className="">
        <Subheadsee subHeading="Recommended for you" path="/tag/recommended" />
        <div className="px-4 flex justify-evenly flex-wrap items-center gap-5 scrollbar-none">
          {recommended.map((item) => (
            <SquareFc
              key={item._id}
              image={item.image}
              name={item.name}
              servingQuantity={item.servingQuantity}
              quantity={item.quantity}
              price={item.price}
              category={item.Category}
              unit={item.unit}
              id={item._id}
              isFav={favFoods.some((food) => food._id === item._id)}
              satisfymessage={satisfymessage}
              description={item.description}
            />
          ))}
        </div>
      </section>

      {/* chef choice */}
      <section className="pb-2">
        <Subheadsee subHeading="Chef's Choice" path="/tag/chefchoice" />
        <div className="px-5 ">
          {chefChoice.map((item) => (
            <HorizontalFc
              key={item._id}
              image={item.image}
              name={item.name}
              description={item.description}
              servingQuantity={item.servingQuantity}
              quantity={item.quantity}
              price={item.price}
              unit={item.unit}
              id={item._id}
              isFav={favFoods.some((food) => food._id === item._id)}
              satisfymessage={satisfymessage}
            />
          ))}
        </div>
      </section>
      {/* bottom bar  */}
      <BottomBar update={update} />
    </div>
  );
};

export default Home;
